const l=document.querySelectorAll("[data-toggle-modal]");l.forEach(e=>{e.addEventListener("click",t=>{t.stopPropagation();const a=t.currentTarget.getAttribute("data-toggle-modal"),o=document.getElementById(a);if(o){const d=o.getAttribute("active")===String(!0);o.setAttribute("active",!d)}})});const c=document.querySelectorAll("[data-modal-move]");c.forEach(e=>{const t=document.getElementById("modal-holder");t&&t.appendChild(e)});
